	// verifying a live 6-digit code generated from the secret. After
	// success, subsequent Logins will require MFA.
	//
	// Errors:
	//
	//	UNAUTHENTICATED     - missing/invalid access_token
	//	FAILED_PRECONDITION - no pending enrollment
	//	INVALID_ARGUMENT    - code is not 6 digits
	//	PERMISSION_DENIED   - code did not match (treat as
	//	                      ERROR_REASON_MFA_CODE_INVALID)
	ConfirmTotpEnrollment(context.Context, *ConfirmTotpEnrollmentRequest) (*emptypb.Empty, error)
